import{_ as a,o as e,c as s,a2 as l}from"./chunks/framework.BflysNKA.js";const u=JSON.parse("{\"title\":\"RimTalk 使用与填写教程\",\"description\":\"\",\"frontmatter\":{},\"headers\":[{\"level\":2,\"title\":\"先填这一组\",\"slug\":\"先填这一组\",\"link\":\"#先填这一组\",\"children\":[]},{\"level\":2,\"title\":\"字段对照\",\"slug\":\"字段对照\",\"link\":\"#字段对照\",\"children\":[]},{\"level\":2,\"title\":\"为什么 Custom 里优先填根地址\",\"slug\":\"为什么-custom-里优先填根地址\",\"link\":\"#为什么-custom-里优先填根地址\",\"children\":[]},{\"level\":2,\"title\":\"第一次测试\",\"slug\":\"第一次测试\",\"link\":\"#第一次测试\",\"children\":[]},{\"level\":2,\"title\":\"常见报错\",\"slug\":\"常见报错\",\"link\":\"#常见报错\",\"children\":[]},{\"level\":2,\"title\":\"拿日志给别人排查\",\"slug\":\"拿日志给别人排查\",\"link\":\"#拿日志给别人排查\",\"children\":[]},{\"level\":2,\"title\":\"接口自测\",\"slug\":\"接口自测\",\"link\":\"#接口自测\",\"children\":[]},{\"level\":2,\"title\":\"下一步\",\"slug\":\"下一步\",\"link\":\"#下一步\",\"children\":[]}],\"relativePath\":\"tools/rimtalk.md\",\"filePath\":\"tools/rimtalk.md\",\"lastUpdated\":1780977600000}"),n={name:"tools/rimtalk.md"};function t(p,i,r,h,o,d){return e(),s("div",null,[...i[0]||(i[0]=[l("<h1 id=\"rimtalk-使用与填写教程\" tabindex=\"-1\">RimTalk 使用与填写教程 <a class=\"header-anchor\" href=\"#rimtalk-使用与填写教程\" aria-label=\"Permalink to &quot;RimTalk 使用与填写教程&quot;\">​</a></h1>\n<p>RimTalk 是环世界 / RimWorld 里把角色对话接到 AI 的工具。接入 小蓝中转站 时，优先选择 <strong>Custom</strong> 或 <strong>OpenAI Compatible</strong> 这一类自定义服务商。</p>\n<p>这类工具最容易填错的是地址。RimTalk 的 Custom 配置里，通常先填根地址：</p>\n<div class=\"language-txt vp-adaptive-theme line-numbers-mode\"><button title=\"Copy Code\" class=\"copy\"></button><span class=\"lang\">txt</span><pre class=\"shiki shiki-themes github-light github-light vp-code\" tabindex=\"0\"><code><span class=\"line\"><span>https://xiaolan1.cn</span></span></code></pre><div class=\"line-numbers-wrapper\" aria-hidden=\"true\"><span class=\"line-number\">1</span><br></div></div>\n<p>模型第一次测试建议填：</p>\n<div class=\"language-txt vp-adaptive-theme line-numbers-mode\"><button title=\"Copy Code\" class=\"copy\"></button><span class=\"lang\">txt</span><pre class=\"shiki shiki-themes github-light github-light vp-code\" tabindex=\"0\"><code><span class=\"line\"><span>gpt-5.4-mini</span></span></code></pre><div class=\"line-numbers-wrapper\" aria-hidden=\"true\"><span class=\"line-number\">1</span><br></div></div>\n<div class=\"tip custom-block\"><p class=\"custom-block-title\">先按这一版填</p><p>如果你在 RimTalk 里选的是 <strong>Custom</strong>，地址先填 <code>https://xiaolan1.cn</code>。不要先填 <code>/v1</code>，也不要先选 Gemini，除非你的模型列表里已经明确能看到 Gemini 模型并且这把 Key 有权限。</p></div>\n<h2 id=\"先填这一组\" tabindex=\"-1\">先填这一组 <a class=\"header-anchor\" href=\"#先填这一组\" aria-label=\"Permalink to &quot;先填这一组&quot;\">​</a></h2>\n<table tabindex=\"0\"><thead><tr><th>RimTalk 里的字段</th><th>填写内容</th></tr></thead><tbody><tr><td>Provider / Mode</td><td><code>Custom</code> 或 <code>OpenAI Compatible</code></td></tr><tr><td>Base URL / API URL / Root URL</td><td><code>https://xiaolan1.cn</code></td></tr><tr><td>API Key</td><td>控制台创建的 <code>sk-...</code> 密钥</td></tr><tr><td>Model</td><td><code>gpt-5.4-mini</code></td></tr><tr><td>Temperature</td><td>保持默认，或先填 <code>0.7</code></td></tr><tr><td>Max Tokens</td><td>保持默认即可；如果必须填写，先用 <code>600</code> 到 <code>1000</code></td></tr></tbody></table>\n<p>Key 建议单独给 RimTalk 建一把，名字可以写成 <code>RimTalk-PC</code>。后面看日志、查余额、停用 Key 都更清楚。</p>\n<h2 id=\"字段对照\" tabindex=\"-1\">字段对照 <a class=\"header-anchor\" href=\"#字段对照\" aria-label=\"Permalink to &quot;字段对照&quot;\">​</a></h2>\n<p>不同版本 RimTalk 的字段名可能不一样。按字段含义来填：</p>\n<table tabindex=\"0\"><thead><tr><th>如果字段写的是</th><th>应该填</th></tr></thead><tbody><tr><td>Base URL / API URL / Root URL</td><td><code>https://xiaolan1.cn</code></td></tr><tr><td>OpenAI Base URL</td><td><code>https://xiaolan1.cn/v1</code></td></tr><tr><td>Chat Endpoint / API Endpoint</td><td><code>https://xiaolan1.cn/v1/chat/completions</code></td></tr><tr><td>Models Endpoint</td><td><code>https://xiaolan1.cn/v1/models</code></td></tr><tr><td>Model Name</td><td><code>gpt-5.4-mini</code>，或从模型广场复制的完整模型名</td></tr></tbody></table>\n<p>如果同一个页面只有一个 URL 输入框，就先看它的标签。写着 Base URL、API URL、Root URL 时填根地址；明确写着 Endpoint 时才填完整接口地址。</p>\n<h2 id=\"为什么-custom-里优先填根地址\" tabindex=\"-1\">为什么 Custom 里优先填根地址 <a class=\"header-anchor\" href=\"#为什么-custom-里优先填根地址\" aria-label=\"Permalink to &quot;为什么 Custom 里优先填根地址&quot;\">​</a></h2>\n<p>RimTalk 的 Custom/OpenAI 客户端通常会把你填的根地址继续拼成 <code>/v1/chat/completions</code> 请求。也就是说，你填根地址时，它实际请求的是：</p>\n<div class=\"language-txt vp-adaptive-theme line-numbers-mode\"><button title=\"Copy Code\" class=\"copy\"></button><span class=\"lang\">txt</span><pre class=\"shiki shiki-themes github-light github-light vp-code\" tabindex=\"0\"><code><span class=\"line\"><span>https://xiaolan1.cn/v1/chat/completions</span></span></code></pre><div class=\"line-numbers-wrapper\" aria-hidden=\"true\"><span class=\"line-number\">1</span><br></div></div>\n<p>如果把 Base URL 填成 <code>https://xiaolan1.cn/v1</code>，有些版本会把请求发到错误路径，结果就是 404；如果填了完整接口但字段本身又会自动拼路径，也可能重复拼接。</p>\n<p>判断规则很简单：<strong>Base URL 填根地址，Endpoint 填完整接口。</strong></p>\n<h2 id=\"第一次测试\" tabindex=\"-1\">第一次测试 <a class=\"header-anchor\" href=\"#第一次测试\" aria-label=\"Permalink to &quot;第一次测试&quot;\">​</a></h2>\n<ol><li>在 RimTalk 保存 Custom 配置。</li><li>先进一个小存档，触发一句很短的角色对话。</li><li>打开 RimTalk 的 API Log / Debug Log。</li><li>确认请求地址最终包含 <code>/v1/chat/completions</code>。</li><li>确认模型名是 <code>gpt-5.4-mini</code>，Key 是你新建的那把。</li></ol>\n<p>第一次只测一条短消息。能正常返回之后，再换更贵、更强或上下文更长的模型。</p>\n<h2 id=\"常见报错\" tabindex=\"-1\">常见报错 <a class=\"header-anchor\" href=\"#常见报错\" aria-label=\"Permalink to &quot;常见报错&quot;\">​</a></h2>\n<table tabindex=\"0\"><thead><tr><th>现象</th><th>常见原因</th><th>怎么处理</th></tr></thead><tbody><tr><td>400</td><td>模型名写错、Key 没权限、请求体格式不符合当前模型</td><td>模型先改成 <code>gpt-5.4-mini</code>；模型名尽量从模型广场复制</td></tr><tr><td>404</td><td>URL 路径填错，最常见是 Base URL 填了 <code>/v1</code></td><td>Custom 里的 Base URL 改成 <code>https://xiaolan1.cn</code></td></tr><tr><td>503</td><td>上游繁忙、当前模型暂不可用，或实际请求地址和你以为的不一样</td><td>先换 <code>gpt-5.4-mini</code> 重试；再看 API Log 里的真实请求地址</td></tr><tr><td>模型列表为空</td><td>Key 权限不足，或 Models Endpoint 填错</td><td>手动填模型名；需要模型列表时用 <code>https://xiaolan1.cn/v1/models</code></td></tr><tr><td>没有任何反应</td><td>RimTalk 没读到新配置，或游戏里没有触发到请求</td><td>保存后重启游戏 / mod，先用最短对话触发一次</td></tr></tbody></table>\n<h2 id=\"拿日志给别人排查\" tabindex=\"-1\">拿日志给别人排查 <a class=\"header-anchor\" href=\"#拿日志给别人排查\" aria-label=\"Permalink to &quot;拿日志给别人排查&quot;\">​</a></h2>\n<p>如果还是不通，不要只发“400 / 404 / 503”。优先复制这三样：</p>\n<ol><li>API Log 里 <code>API request:</code> 后面的真实 URL。</li><li>请求 JSON 里的 <code>model</code> 字段。</li><li>错误返回内容。</li></ol>\n<p>发给别人前，把 <code>Authorization</code>、<code>Bearer sk-...</code> 和完整 Key 打码。</p>\n<h2 id=\"接口自测\" tabindex=\"-1\">接口自测 <a class=\"header-anchor\" href=\"#接口自测\" aria-label=\"Permalink to &quot;接口自测&quot;\">​</a></h2>\n<p>如果想先确认 Key 本身能不能用，可以在 Windows PowerShell 里测模型列表：</p>\n<div class=\"language-powershell vp-adaptive-theme line-numbers-mode\"><button title=\"Copy Code\" class=\"copy\"></button><span class=\"lang\">powershell</span><pre class=\"shiki shiki-themes github-light github-light vp-code\" tabindex=\"0\"><code><span class=\"line\"><span>curl.exe https://xiaolan1.cn/v1/models -H &quot;Authorization: Bearer sk-你的Key&quot;</span></span></code></pre><div class=\"line-numbers-wrapper\" aria-hidden=\"true\"><span class=\"line-number\">1</span><br></div></div>\n<p>再测一次最小聊天请求：</p>\n<div class=\"language-powershell vp-adaptive-theme line-numbers-mode\"><button title=\"Copy Code\" class=\"copy\"></button><span class=\"lang\">powershell</span><pre class=\"shiki shiki-themes github-light github-light vp-code\" tabindex=\"0\"><code><span class=\"line\"><span>curl.exe https://xiaolan1.cn/v1/chat/completions -H &quot;Content-Type: application/json&quot; -H &quot;Authorization: Bearer sk-你的Key&quot; -d &quot;{\\&quot;model\\&quot;:\\&quot;gpt-5.4-mini\\&quot;,\\&quot;messages\\&quot;:[{\\&quot;role\\&quot;:\\&quot;user\\&quot;,\\&quot;content\\&quot;:\\&quot;test\\&quot;}]}&quot;</span></span></code></pre><div class=\"line-numbers-wrapper\" aria-hidden=\"true\"><span class=\"line-number\">1</span><br></div></div>\n<p>这两步能通，说明 Key 和小蓝接口本身是通的；RimTalk 里再重点看 URL 字段、模型名和 Custom 模式。</p>\n<h2 id=\"下一步\" tabindex=\"-1\">下一步 <a class=\"header-anchor\" href=\"#下一步\" aria-label=\"Permalink to &quot;下一步&quot;\">​</a></h2>\n<ul><li><a href=\"/guide/create-key\">创建专属 Key</a></li><li><a href=\"/guide/quick-start\">快速接入</a></li><li><a href=\"/api/chat\">聊天接口说明</a></li></ul>",69)])])}const b=a(n,[["render",t]]);export{u as __pageData,b as default};
